module RefModule (
    input clk,
    input rst,
    input si,
    output [7:0] po
);

    reg [7:0] sr;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
        if (rst)
            sr <= 8'b00000000;
        else
            sr <= {sr[6:0], si};
    end

    assign po = sr;

endmodule
